#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv1 = (vUv - 0.5 + 0.2 * q2) * uAspect.xy;
    lea = 0;
    int anz = 4;
    for (float n = anz; n > 0; n--) {
        dist = (1.5 + q2) * 0.33 * n / 6;
        uv4 = 256 * (dist * uv1) * q10;

        float aa = (1.0 + q3 / 2) * n / anz + q1 * (12 + uv1.x * 0) /2;
        uv4 = multiply(uv4, mat2(cos(aa), -sin(aa), sin(aa), cos(aa)));
        stripe = (16 - 0.8 * abs(floor(uv4.x)));
        uv4.y += stripe/2 * q5 + (16 - stripe) * q6 - 8.0 * n;

        noise = texture(sampler_pw_noise_lq, uv4 / 256);
        smask = sat(64 * (noise.b - (0.88 - (stripe / 36) * 0.1))); // Keep provided density

        aa = (noise.g - 0.5) * q8;
        uv5 = multiply(fract(uv4) - 0.5, mat2(cos(aa), -sin(aa), sin(aa), cos(aa)));

        dr = (abs(sin(uv4.y * 0.5 + 2 * q7 * noise.r)));
        uv5.x *= 1.7; // Keep provided stretch horizontally
        uv5.y *= 2.4; // Keep provided compression vertically

        struc = texture(sampler_noise_hq, 0.5 * aTan2(uv5.x, uv5.y + 0.4)) - 0.5;
        uv6 = uv5;
        uv5 += struc * n * 0.20 * (noise.r);
        h = smask * sat(8 - 12 * length(uv5)); // Keep provided intensity

        // Modified: White, pinkish, and red petal colors
        float color_sel = noise.r; // Use noise to select color
        vec3 petal_color;
        if (color_sel < 0.33) {
            petal_color = vec3(1.0, 1.0, 1.0); // White
        } else if (color_sel < 0.66) {
            petal_color = vec3(1.0, 0.8, 0.85); // Pinkish
        } else {
            petal_color = vec3(1.0, 0.5, 0.5); // Red
        }
        neu = h * petal_color * (0.8 + 0.2 * noise.g); // Vary brightness with noise

        lea = mix(lea, neu, h);
    }

    ret = lea; // Keep original output

  fragColor = ret;
}

