void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  //MilkDrop3 Flip Mode:
vUv = 1-vUv;
 ;
uv0 = vUv;
uv1 = (vUv-.5)*uAspect.xy;

uv1 = (vUv - .5) * uAspect.xy;
float stars = 0; float dist, inten;
int n = 1;
int anz = 4;
while (n <= anz) {
  dist = (1-fract(1.0/anz*n+.10*uTime)) * (1-.2*vRadius);
  inten =  (1-dist);
  uv3 = (uv1+vec2(q1,q2));
   uv4 = 64*dist*uv3;
  smask = (texture(sampler_pw_noise_lq,uv4/256)).g-.9;
  stars += max(stars,clamp01(inten*(0.11/length(abs(fract(uv4)-0.47))*smask)));
n++;
}
uv2 = uv1 - vec2(q5,q6);
float beat = (audioMid - 0.45) * (audioMid > 0.45)*2;
float flash = .01/(length(uv2))*min(3,pow(beat,1));
flash *= flash/(abs(fract(3*aTan2(uv2.x,uv2.y)+uTime*2)-.5));
