//ret = clamp01(0.022/length(sin(uv3)))*vec3(0.2,2.6,0.1); //MilkDrop2077 color mod
ret += clamp01(pow(stars,2));
ret *= clamp01(1-2*lum(ret1));
ret +=  ret1;
ret -= 0.1;
//ret += 2*clamp01(flash)*vec3(2.2,2.9,0.7); //MilkDrop2077 color mod
//MilkDrop3 Color Mode:
ret /= vec3(1.0,1.4,0.7);

  fragColor = ret;
